import * as AasJsonization from "../src/jsonization";
import * as AasTypes from "../src/types";

test("Result deserializes Ok OK", () => {
  const jsonable = "ok";

  const literalOrError = AasJsonization.resultFromJsonable(
    jsonable
  );

  expect(literalOrError.error).toBeNull();
  const parsedLiteral = literalOrError.mustValue();

  expect(parsedLiteral).toStrictEqual(
    AasTypes.Result.Ok
  );
});

test("Result deserializes NotOk OK", () => {
  const jsonable = "not-ok";

  const literalOrError = AasJsonization.resultFromJsonable(
    jsonable
  );

  expect(literalOrError.error).toBeNull();
  const parsedLiteral = literalOrError.mustValue();

  expect(parsedLiteral).toStrictEqual(
    AasTypes.Result.NotOk
  );
});

test("Result deserialization fail", () => {
  const jsonable = "invalid-literal";

  const literalOrError = AasJsonization.resultFromJsonable(
    jsonable
  );

  expect(literalOrError.error.message).toStrictEqual(
    "Not a valid string representation of a literal of Result: invalid-literal"
  );
});

